import { expect } from "@playwright/test";
import { MockClient } from "request-mocking-protocol";
import { test as base } from "./test-fixture";

export const test = base.extend<{ mockServerRequest: MockClient }>({
  mockServerRequest: async ({ context }, use) => {
    const mockClient = new MockClient();
    mockClient.onChange = async (headers) =>
      context.setExtraHTTPHeaders(headers);
    await use(mockClient);
  },
});

const descriptionText = "Help us build momentum with a quick sign-up.";
const actionPageUrlPattern =
  /https?:\/\/[^/]+\/public\/v3\/action_pages\/[^/?]+/;
const leadSubmissionUrlPattern =
  /https?:\/\/[^/]+\/public\/v3\/submissions\/lead\/?(?:\?.*)?$/;

const mockActionPage = {
  id: "ap_123",
  headerTitleText: "Join the Movement",
  description: descriptionText,
  account: {
    id: "acct_123",
    displayName: "Demo Org",
    allowCustomCss: false,
    slug: "demo-org",
  },
};

async function mockPublicActionPage(mockServerRequest: MockClient) {
  await mockServerRequest.GET(actionPageUrlPattern, { body: mockActionPage });
}

async function mockLeadSubmission(
  mockServerRequest: MockClient,
  body: Record<string, unknown> = {},
) {
  await mockServerRequest.PUT(leadSubmissionUrlPattern, {
    body: {
      id: "lead_123",
      actionPage: {
        id: "ap_123",
        name: "Join the Movement",
        pageType: "lead",
      },
      addressAttributes: {
        city: "Austin",
        country: "USA",
        line1: "123 Main St",
        postalCode: "78701",
        region: "TX",
      },
      callbackUrl: null,
      ...body,
    },
  });
}

test("shows the heading", async ({ page, mockServerRequest }) => {
  await mockPublicActionPage(mockServerRequest);

  await page.goto("/lead/demo-org/lead-token");

  await expect(
    page.getByRole("heading", { name: "Join the Movement" }),
  ).toBeVisible();
});

test("shows the description when provided", async ({
  page,
  mockServerRequest,
}) => {
  await mockPublicActionPage(mockServerRequest);

  await page.goto("/lead/demo-org/lead-token");

  await expect(page.getByText(descriptionText)).toBeVisible();
});

test.only("shows all form fields", async ({ page, mockServerRequest }) => {
  await mockPublicActionPage(mockServerRequest);

  await page.goto("/lead/demo-org/lead-token");

  // Text inputs
  await expect(page.getByLabel("Email", { exact: true })).toBeVisible();
  await expect(page.getByLabel("Phone")).toBeVisible();
  await expect(page.getByLabel("First name")).toBeVisible();
  await expect(page.getByLabel("Last name")).toBeVisible();
  await expect(page.getByLabel("/address/i")).toBeVisible();
  await expect(page.getByLabel("Address line 2")).toBeVisible();
  await expect(page.getByLabel("City")).toBeVisible();
  await expect(page.getByLabel("State")).toBeVisible();
  await expect(page.getByLabel("Postal code")).toBeVisible();
  await expect(page.getByLabel("Country")).toBeVisible();

  // Checkbox
  await expect(page.getByLabel("Send me updates by email")).toBeVisible();

  // Submit button
  await expect(page.getByRole("button", { name: "Submit" })).toBeVisible();

  // Login link
  await expect(page.getByText("Already have an account?")).toBeVisible();
});

test("enables submit only after required fields are filled and submits successfully", async ({
  page,
  mockServerRequest,
}) => {
  await mockPublicActionPage(mockServerRequest);

  await page.goto("/lead/demo-org/lead-token");

